     1→use criterion::{black_box, criterion_group, criterion_main, BenchmarkId, Criterion};
     2→use ndarray::{Array1, Array2};
     3→use rand::prelude::*;
     4→use rand_distr::{Normal, Uniform};
     5→use stats_models::{Gaussian, Glm, Lm, Poisson};
     6→
     7→fn generate_regression_data(n_obs: usize, n_vars: usize, seed: u64) -> (Array2<f64>, Array1<f64>) {
     8→    let mut rng = StdRng::seed_from_u64(seed);
     9→    let normal = Normal::new(0.0, 1.0).unwrap();
    10→    let uniform = Uniform::new(-1.0, 1.0);
    11→
    12→    // Generate design matrix with intercept
    13→    let mut x = Array2::zeros((n_obs, n_vars + 1));
    14→    x.column_mut(0).fill(1.0); // Intercept
    15→
    16→    for i in 0..n_obs {
    17→        for j in 1..=n_vars {
    18→            x[[i, j]] = rng.sample(normal);
    19→        }
    20→    }
    21→
    22→    // Generate true coefficients
    23→    let true_beta: Array1<f64> = Array1::from_iter((0..=n_vars).map(|_| rng.sample(uniform)));
    24→
    25→    // Generate response: y = X*β + ε
    26→    let linear_pred = x.dot(&true_beta);
    27→    let noise: Array1<f64> =
    28→        Array1::from_iter((0..n_obs).map(|_| rng.sample(Normal::new(0.0, 0.1).unwrap())));
    29→    let y = linear_pred + noise;
    30→
    31→    (x, y)
    32→}
    33→
    34→fn generate_count_data(n_obs: usize, n_vars: usize, seed: u64) -> (Array2<f64>, Array1<f64>) {
    35→    let mut rng = StdRng::seed_from_u64(seed);
    36→    let normal = Normal::new(0.0, 0.5).unwrap();
    37→    let uniform = Uniform::new(-0.5, 0.5);
    38→
    39→    // Generate design matrix with intercept
    40→    let mut x = Array2::zeros((n_obs, n_vars + 1));
    41→    x.column_mut(0).fill(1.0); // Intercept
    42→
    43→    for i in 0..n_obs {
    44→        for j in 1..=n_vars {
    45→            x[[i, j]] = rng.sample(normal);
    46→        }
    47→    }
